/* BTCircleChart — circle chart wrapper */

.bt-circle-chart {
  position: relative;
  display: inline-block;
}

.bt-circle-chart__rounded-svg {
  display: block;
  overflow: visible;
}

.bt-circle-chart__rounded-arc {
  paint-order: stroke fill;
}

.bt-circle-chart__rounded-arc-border {
  paint-order: stroke fill;
}

/* Connector lines SVG overlay */
.bt-circle-chart__connectors {
  position: absolute;
  inset: 0;
  overflow: visible;
  pointer-events: none;
}

.bt-circle-chart__connector-line {
  stroke: var(--border-primary);
  stroke-width: 1;
  fill: none;
}

/* External badge labels overlay */
.bt-circle-chart__labels {
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.bt-circle-chart__badge {
  position: absolute;
  display: flex;
  flex-direction: column;
  align-items: center;
  transform: translate(-50%, -50%);
  text-align: center;
  line-height: 1.4;
}

.bt-circle-chart__badge-label {
  font-size: var(--typography-font-size-2xs);
  font-weight: 500;
  color: var(--text-secondary);
  font-family: var(--typography-font-family-sans, "Geist", system-ui);
}

.bt-circle-chart__badge-value {
  font-size: var(--typography-font-size-2xs);
  font-weight: 700;
  color: var(--text-primary);
  font-family: var(--typography-font-family-sans, "Geist", system-ui);
}

/* DonutRounded: rounded segment ends via SVG stroke-linecap */
.bt-circle-chart--donut-rounded .apexcharts-pie-area {
  stroke-linecap: round !important;
  stroke-linejoin: round !important;
  paint-order: stroke fill !important;
}

.bt-circle-chart--donut-rounded .apexcharts-series path {
  stroke-linecap: round !important;
  stroke-linejoin: round !important;
}

/* Remove ApexCharts default tooltip chrome */
.bt-circle-chart .apexcharts-tooltip {
  background: transparent !important;
  border: none !important;
  box-shadow: none !important;
  overflow: visible !important;
}

/**
 * BTCircleChart — pie / donut / donutRounded chart molecule (ApexCharts wrapper).
 *
 * Figma node 3404:1813 · M - CircleChart
 *
 * @example
 * ```tsx
 * <BTCircleChart sections={[{value:40,color:'#0EA5E9',label:'A'}]} />
 * <BTCircleChart sections={sections} variant="donut" />
 * <BTCircleChart sections={sections} variant="donutRounded" />
 * ```
 */
import './BTCircleChart.css';
import './internal/chart-tooltip';
import { useMemo } from 'react';
import ReactApexChart from 'react-apexcharts';
import type { ApexOptions } from 'apexcharts';
import type { BTCircleSection, BTCircleChartVariant } from './BTCircleChart.types';
import { buildTooltipHtml } from './internal/chart-tooltip';
import { btChartBase } from './internal/chart-apex.utils';

export interface BTCircleChartProps {
  sections: BTCircleSection[];
  variant?: BTCircleChartVariant;
  /** Width/height in px */
  size?: number;
}

interface RoundedArcSegment {
  color: string;
  d: string;
}

function polarToCartesian(cx: number, cy: number, radius: number, angleDeg: number) {
  const angleRad = ((angleDeg - 90) * Math.PI) / 180;
  return {
    x: cx + radius * Math.cos(angleRad),
    y: cy + radius * Math.sin(angleRad),
  };
}

function buildRoundedArcPath(
  cx: number,
  cy: number,
  radius: number,
  startAngle: number,
  endAngle: number,
) {
  const start = polarToCartesian(cx, cy, radius, startAngle);
  const end = polarToCartesian(cx, cy, radius, endAngle);
  const delta = ((endAngle - startAngle) % 360 + 360) % 360;
  const largeArcFlag = delta > 180 ? 1 : 0;
  return `M ${start.x} ${start.y} A ${radius} ${radius} 0 ${largeArcFlag} 1 ${end.x} ${end.y}`;
}

export function BTCircleChart({
  sections,
  variant = 'pie',
  size = 208,
}: BTCircleChartProps) {
  const isPie          = variant === 'pie';
  const isDonut        = variant === 'donut';
  const isDonutRounded = variant === 'donutRounded';

  const total = sections.reduce((s, sec) => s + sec.value, 0);

  const donutSize = isPie ? '0%' : isDonutRounded ? '60%' : '58%';
  const roundedArcSegments = useMemo<RoundedArcSegment[]>(() => {
    if (!isDonutRounded || total <= 0) return [];

    const cx = size / 2;
    const cy = size / 2;
    const radius = size * 0.305;
    const gapAngle = 9;

    let currentAngle = -90;
    return sections.map((section) => {
      const sweep = (section.value / total) * 360;
      const safeSweep = Math.max(sweep - gapAngle, 0);
      const startAngle = currentAngle + gapAngle / 2;
      const endAngle = startAngle + safeSweep;
      currentAngle += sweep;

      return {
        color: section.color,
        d: buildRoundedArcPath(cx, cy, radius, startAngle, endAngle),
      };
    });
  }, [isDonutRounded, sections, size, total]);

  // ── Badge label positions + connector line endpoints ─────────────────────
  // outerR  = rendered ring outer edge (~90% of half-size, accounting for ApexCharts padding)
  // Connector: outerR+4 → outerR+28 (4px gap from ring, 24px line)
  // Badge center: outerR+34 (6px after line end)
  const badgePositions = useMemo(() => {
    if (total === 0) return [];
    const cx     = size / 2;
    const cy     = size / 2;
    const outerR = size / 2 * 0.84;
    const lineR1 = outerR + (isPie ? 10 : 6);
    const lineR2 = outerR + 26;
    const badgeR = outerR + 40;

    let cumAngle = -90;
    return sections.map((sec) => {
      const sweep = (sec.value / total) * 360;
      const mid   = cumAngle + sweep / 2;
      const rad   = (mid * Math.PI) / 180;
      cumAngle   += sweep;
      const cosA  = Math.cos(rad);
      const sinA  = Math.sin(rad);
      return {
        label: sec.label ?? '',
        pct:   `${((sec.value / total) * 100).toFixed(0)}%`,
        x:  cx + badgeR * cosA,
        y:  cy + badgeR * sinA,
        lx1: cx + lineR1 * cosA,
        ly1: cy + lineR1 * sinA,
        lx2: cx + lineR2 * cosA,
        ly2: cy + lineR2 * sinA,
      };
    });
  }, [sections, total, size, isPie]);

  const options = useMemo<ApexOptions>(() => ({
    chart: {
      ...btChartBase(),
      type: 'donut',
      width: size,
      height: size,
    },
    plotOptions: {
      pie: {
        startAngle: -90,
        endAngle: 270,
        customScale: isPie ? 0.96 : isDonutRounded ? 0.88 : 0.9,
        donut: { size: donutSize },
      },
    },
    // Donut is continuous. DonutRounded adds subtle gaps so rounded ends read clearly.
    stroke: isPie
      ? { show: false }
      : isDonut
        ? { show: false }
        : { show: true, width: 10, colors: ['var(--bg-primary)'] },
    dataLabels: { enabled: false },
    legend:     { show: false },
    colors: sections.map((s) => s.color),
    labels: sections.map((s) => s.label ?? ''),
    tooltip: {
      custom({ seriesIndex }: { seriesIndex: number }) {
        const sec = sections[seriesIndex];
        if (!sec) return buildTooltipHtml(null, []);
        const pct   = total > 0
          ? ((sec.value / total) * 100).toFixed(0)
          : '0';
        const title = sec.label ? `${sec.label} ${pct}%` : `${pct}%`;
        return buildTooltipHtml(title, [], { placement: 'none' });
      },
    },
  }), [sections, size, donutSize, isPie, isDonut, total]);

  const apexSeries = sections.map((s) => s.value);
  const roundedStrokeWidth = size * 0.122;
  const roundedBorderWidth = size * 0.148;

  return (
    <div
      className={`bt-circle-chart${isDonutRounded ? ' bt-circle-chart--donut-rounded' : ''}`}
      style={{ width: size, height: size }}
    >
      {isDonutRounded ? (
        <svg
          className="bt-circle-chart__rounded-svg"
          width={size}
          height={size}
          viewBox={`0 0 ${size} ${size}`}
          aria-hidden="true"
        >
          {roundedArcSegments.map((segment, index) => (
            <g key={index}>
              <path
                d={segment.d}
                fill="none"
                stroke="var(--bg-primary)"
                strokeWidth={roundedBorderWidth}
                strokeLinecap="round"
                strokeLinejoin="round"
                className="bt-circle-chart__rounded-arc-border"
              />
              <path
                d={segment.d}
                fill="none"
                stroke={segment.color}
                strokeWidth={roundedStrokeWidth}
                strokeLinecap="round"
                strokeLinejoin="round"
                className="bt-circle-chart__rounded-arc"
              />
            </g>
          ))}
        </svg>
      ) : (
        <ReactApexChart
          type="donut"
          width={size}
          height={size}
          options={options}
          series={apexSeries}
        />
      )}

      {/* Connector lines from ring edge to badges */}
      <svg
        className="bt-circle-chart__connectors"
        style={{ width: size, height: size }}
        aria-hidden="true"
      >
        {badgePositions.map((badge, i) => (
          <line
            key={i}
            x1={badge.lx1}
            y1={badge.ly1}
            x2={badge.lx2}
            y2={badge.ly2}
            className="bt-circle-chart__connector-line"
          />
        ))}
      </svg>

      {/* External badge labels */}
      <div className="bt-circle-chart__labels">
        {badgePositions.map((badge, i) => (
          <div
            key={i}
            className="bt-circle-chart__badge"
            style={{ left: badge.x, top: badge.y }}
          >
            {badge.label && (
              <span className="bt-circle-chart__badge-label">{badge.label}</span>
            )}
            <span className="bt-circle-chart__badge-value">{badge.pct}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

/* BTChart tooltip balloon — aligned to BTTooltip / Figma 3404:2299. */

.bt-chart-tooltip {
  display: flex;
  align-items: stretch;
  width: max-content;
  max-width: min(220px, calc(100vw - var(--space-xl)));
  color: var(--text-inverse);
  font-family: var(--typography-font-family-sans, "Geist", system-ui);
}

.bt-chart-tooltip--left {
  flex-direction: row-reverse;
}

.bt-chart-tooltip--right {
  flex-direction: row;
}

.bt-chart-tooltip--plain {
  display: block;
}

.bt-chart-tooltip__arrow-col {
  position: relative;
  width: 8px;
  align-self: stretch;
  flex-shrink: 0;
  z-index: 1;
}

.bt-chart-tooltip--left .bt-chart-tooltip__arrow-col {
  margin-left: -1px;
}

.bt-chart-tooltip--right .bt-chart-tooltip__arrow-col {
  margin-right: -1px;
}

.bt-chart-tooltip__arrow {
  position: absolute;
  top: 50%;
  display: block;
  transform: translateY(-50%);
}

.bt-chart-tooltip--left .bt-chart-tooltip__arrow {
  right: 0;
}

.bt-chart-tooltip--right .bt-chart-tooltip__arrow {
  left: 0;
}

.bt-chart-tooltip__body {
  min-width: 148px;
  padding: var(--space-lg);
  background: var(--bg-inverse);
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow-elevation-xl);
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
  box-sizing: border-box;
}

.bt-chart-tooltip--plain .bt-chart-tooltip__body {
  min-width: 0;
}

.bt-chart-tooltip__title {
  margin: 0;
  color: var(--text-inverse);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  text-align: center;
}

.bt-chart-tooltip__separator {
  height: 1px;
  background: rgba(255, 255, 255, 0.2);
}

.bt-chart-tooltip__row {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}

.bt-chart-tooltip__row + .bt-chart-tooltip__row {
  margin-block-start: var(--space-xs);
}

.bt-chart-tooltip__swatch {
  width: 12px;
  height: 12px;
  flex-shrink: 0;
  border-radius: 2px;
}

.bt-chart-tooltip__label {
  flex: 1;
  min-width: 0;
  color: var(--text-inverse);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-chart-tooltip__value {
  color: var(--text-inverse);
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  line-height: var(--typography-line-height-xs);
  white-space: nowrap;
}

// chart-tooltip.ts — builds the HTML string for ApexCharts custom tooltip.
// Renders a dark balloon matching Figma 3404:2299 (BTChartCard tooltip spec).

import type { BTChartTooltipItem } from './chart.types';

export interface BTChartTooltipOptions {
  placement?: 'left' | 'right' | 'none';
}

/**
 * Generates an HTML string for use in ApexCharts `tooltip.custom` callback.
 *
 * @param title  Optional headline centered at the top (e.g. "Jan", "A 40%").
 * @param items  Optional legend rows below the separator.
 * @returns HTML string ready to be returned from the ApexCharts custom function.
 */
export function buildTooltipHtml(
  title: string | null | undefined,
  items: BTChartTooltipItem[],
  options: BTChartTooltipOptions = {},
): string {
  const hasItems = items.length > 0;
  const placement = options.placement ?? 'left';
  const arrowPath = placement === 'right'
    ? 'M8 0 L1 7 Q0 8 1 9 L8 16 Z'
    : 'M0 0 L7 7 Q8 8 7 9 L0 16 Z';

  const titleHtml = title
    ? `<div class="bt-chart-tooltip__title">${escapeHtml(title)}</div>`
    : '';

  const separatorHtml =
    title && hasItems
      ? `<div class="bt-chart-tooltip__separator"></div>`
      : '';

  const rowsHtml = hasItems
    ? items
        .map(
          (item) => `
        <div class="bt-chart-tooltip__row">
          <span class="bt-chart-tooltip__swatch" style="background:${item.color}"></span>
          ${item.label ? `<span class="bt-chart-tooltip__label">${escapeHtml(item.label)}</span>` : ''}
          <span class="bt-chart-tooltip__value">${escapeHtml(item.value)}</span>
        </div>`,
        )
        .join('')
    : '';

  const bodyHtml = `
    <div class="bt-chart-tooltip__body">
      ${titleHtml}
      ${separatorHtml}
      ${rowsHtml}
    </div>
  `;

  if (placement === 'none') {
    return `<div class="bt-chart-tooltip bt-chart-tooltip--plain">${bodyHtml}</div>`;
  }

  return `
    <div class="bt-chart-tooltip bt-chart-tooltip--${placement}">
      <div class="bt-chart-tooltip__arrow-col" aria-hidden="true">
        <svg class="bt-chart-tooltip__arrow" width="8" height="16" viewBox="0 0 8 16" fill="none">
          <path d="${arrowPath}" fill="var(--bg-inverse)"></path>
        </svg>
      </div>
      ${bodyHtml}
    </div>
  `;
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// chart-apex.utils.ts — shared ApexCharts option fragments used by all chart types.

import type { ApexOptions } from 'apexcharts';

/** Shared axis label style (10px medium, --text-secondary, Geist). */
export function btAxisLabelStyle(): object {
  return {
    fontFamily: 'var(--typography-font-family-sans, "Geist", system-ui)',
    fontSize: '10px',
    fontWeight: 500,
    colors: 'var(--text-secondary)',
  };
}

/** Shared grid options — horizontal lines only. */
export function btGridOptions(): NonNullable<ApexOptions['grid']> {
  return {
    show: true,
    borderColor: 'var(--border-primary)',
    strokeDashArray: 0,
    xaxis: { lines: { show: false } },
    yaxis: { lines: { show: true } },
    padding: { top: 0, right: 8, bottom: 0, left: 4 },
  };
}

/** Shared toolbar / zoom disable config. */
export function btChartBase(): NonNullable<ApexOptions['chart']> {
  return {
    toolbar: { show: false },
    zoom: { enabled: false },
    fontFamily: 'var(--typography-font-family-sans, "Geist", system-ui)',
    background: 'transparent',
    animations: { enabled: false },
    parentHeightOffset: 0,
  };
}

/**
 * Infer Y-axis max: round the data max up to the nearest 20.
 * Matches Flutter _inferMaxY logic.
 */
export function inferMaxY(values: number[]): number {
  const max = values.length > 0 ? Math.max(...values) : 0;
  if (max === 0) return 100;
  return Math.ceil(max / 20) * 20;
}

// Internal chart types — shared across BTBarChart, BTLineChart, BTCircleChart, BTChartCard.
// Do NOT re-export from component barrels.

/** Single bar datum for BTBarChart basic variant. */
export interface BTBarData {
  value: number;
  /** x-axis label */
  label?: string;
}

/** One rod within a grouped or stacked bar. */
export interface BTBarItem {
  value: number;
  /** CSS color or var(--token) */
  color: string;
  /** Series name shown in tooltip */
  label?: string;
}

/** One x-position group for BTBarChart grouped variant. */
export interface BTBarGroupData {
  /** x-axis label */
  label?: string;
  bars: BTBarItem[];
}

/** One stacked bar for BTBarChart stacked variant. */
export interface BTStackedBarData {
  /** x-axis label */
  label?: string;
  segments: BTBarItem[];
}

/** One (x, y) data point for BTLineChart. */
export interface BTLineSpot {
  x: number;
  y: number;
}

/** One series for BTLineChart. */
export interface BTLineSeries {
  spots: BTLineSpot[];
  /** CSS color or var(--token) */
  color: string;
  /** Series name shown in tooltip */
  label?: string;
}

/** One section for BTCircleChart. */
export interface BTCircleSection {
  value: number;
  /** CSS color or var(--token) */
  color: string;
  /** Section label shown on badge and in tooltip */
  label?: string;
}

/** Legend item shown in BTChartCard. */
export interface BTChartLegendItem {
  label: string;
  /** CSS color or var(--token) */
  color: string;
}

/** Summary metric shown in BTChartCard header area. */
export interface BTChartSummaryItem {
  label: string;
  value: string;
  unit?: string;
}

/** One row inside the chart tooltip balloon. */
export interface BTChartTooltipItem {
  /** Swatch color */
  color: string;
  /** Series name — empty string hides the label column */
  label: string;
  /** Formatted value string */
  value: string;
}
